import {
	ApiError,
	AuthError,
	ConduitError,
	InsufficientCreditsError,
	RateLimitError,
	ValidationError,
} from "../errors";
import { backoffMs, getHeader, jitter, randomId, withDeadline } from "../utils";

type SSEStreamOptions = {
	signal?: AbortSignal;
	lastEventId?: string;
};
type SSEEvent<T = unknown> = {
	id?: string;
	event: string;
	data: T;
};
type Telemetry = {
	onRequest?: (ctx: {
		method: string;
		url: string;
		requestId?: string;
	}) => void;
	onResponse?: (ctx: {
		status: number;
		url: string;
		requestId?: string;
		durationMs: number;
	}) => void;
	onError?: (ctx: {
		url: string;
		requestId?: string;
		error: unknown;
		context?: Record<string, unknown>;
	}) => void;
};
type TransportOptions = {
	apiKey: string;
	authHeaderName?: string;
	baseUrl: string;
	timeoutMs: number;
	maxRetries: number;
	defaultHeaders?: Record<string, string>;
	fetch?: typeof fetch;
	telemetry?: Telemetry;
	userAgent?: string;
};
type RequestOptions = {
	method: "GET" | "POST" | "DELETE" | "PUT" | "PATCH";
	path: string;
	query?: Record<string, string | number | boolean | undefined>;
	headers?: Record<string, string | undefined>;
	body?: unknown;
	idempotencyKey?: string;
	requestId?: string;
	signal?: AbortSignal;
	retryable?: boolean;
};
type TransportResponse<T> = {
	data: T;
	status: number;
	requestId?: string;
	headers: Headers;
};

const LEADING_SLASH_REGEX = /^\//;

function buildUrl(
	baseUrl: string,
	path: string,
	query?: RequestOptions["query"],
): string {
	const url = new URL(
		path.replace(LEADING_SLASH_REGEX, ""),
		baseUrl.endsWith("/") ? baseUrl : `${baseUrl}/`,
	);
	if (!query) return url.toString();
	for (const [k, v] of Object.entries(query)) {
		if (v === undefined) continue;
		url.searchParams.set(k, String(v));
	}
	return url.toString();
}

async function readBody(
	res: Response,
): Promise<{ parsed: unknown; text: string }> {
	const text = await res.text();
	if (!text) return { parsed: null, text: "" };
	try {
		return { parsed: JSON.parse(text), text };
	} catch {
		return { parsed: text, text };
	}
}

function coerceApiError(res: Response, parsed: unknown): ApiError {
	const requestId = res.headers.get("x-request-id") ?? undefined;
	const normalized = normalizeApiErrorParsed(parsed, res.status);
	const code = normalized.code;
	const message = normalized.message;
	const details = normalized.details;

	if (res.status === 401 || res.status === 403) {
		return new AuthError(message, {
			code,
			details,
			requestId,
			status: res.status,
		});
	}

	if (res.status === 422) {
		return new ValidationError(message, {
			code,
			details,
			requestId,
			status: res.status,
		});
	}

	if (res.status === 402 && code === "insufficient_credits") {
		const credits = normalizeCredits(details);
		return new InsufficientCreditsError(message, {
			code,
			details: credits,
			requestId,
			status: res.status,
		});
	}

	if (res.status === 429) {
		const err = new RateLimitError(message, {
			code,
			details,
			requestId,
			status: res.status,
		});
		err.retryAfterMs = parseRetryAfterMs(res.headers.get("retry-after"));
		return err;
	}

	return new ApiError(message, {
		code,
		details,
		requestId,
		status: res.status,
	});
}

function normalizeApiErrorParsed(
	parsed: unknown,
	status: number,
): { code?: string; message: string; details: unknown } {
	if (typeof parsed === "string") {
		return {
			details: parsed,
			message: parsed,
		};
	}
	if (!(parsed && typeof parsed === "object")) {
		return {
			details: parsed,
			message: `Request failed with status ${status}`,
		};
	}
	const obj = parsed as Record<string, unknown>;
	const err =
		obj.error && typeof obj.error === "object"
			? (obj.error as Record<string, unknown>)
			: obj;
	return {
		code: typeof err.code === "string" ? err.code : undefined,
		details: "details" in err ? err.details : parsed,
		message:
			typeof err.message === "string"
				? err.message
				: `Request failed with status ${status}`,
	};
}

function parseRetryAfterMs(value: string | null): number | undefined {
	if (!value) return;
	const sec = Number(value);
	if (!Number.isFinite(sec) || sec < 0) return;
	return sec * 1000;
}

function normalizeCredits(details: unknown): {
	required?: number;
	available?: number;
} {
	const root = readCredits(details);
	if (root.required !== undefined || root.available !== undefined) return root;
	if (!(details && typeof details === "object")) return {};
	if (!("details" in details)) return {};
	return readCredits((details as { details?: unknown }).details);
}

function readCredits(value: unknown): {
	required?: number;
	available?: number;
} {
	if (!(value && typeof value === "object")) return {};
	const obj = value as Record<string, unknown>;
	const required =
		typeof obj.required === "number" && Number.isFinite(obj.required)
			? obj.required
			: undefined;
	const available =
		typeof obj.available === "number" && Number.isFinite(obj.available)
			? obj.available
			: undefined;
	return { available, required };
}

function shouldRetry(
	req: RequestOptions,
	err: unknown,
): { retry: boolean; retryAfterMs?: number } {
	if (!req.retryable) return { retry: false };
	if (err instanceof RateLimitError) {
		return { retry: true, retryAfterMs: err.retryAfterMs };
	}
	if (err instanceof ApiError) {
		return { retry: err.status >= 500 && err.status <= 599 };
	}
	if (err instanceof TypeError) return { retry: true };
	return { retry: false };
}

function isNetworkError(err: unknown): boolean {
	if (err instanceof TypeError) return true;
	if (!err || typeof err !== "object") return false;
	if (!("code" in err)) return false;
	if (typeof err.code !== "string") return false;
	return [
		"FailedToOpenSocket",
		"ECONNREFUSED",
		"ECONNRESET",
		"ETIMEDOUT",
		"ENOTFOUND",
		"EAI_AGAIN",
	].includes(err.code);
}

function encodeRequestBody(body: unknown) {
	if (body === undefined) return;
	if (typeof FormData !== "undefined" && body instanceof FormData) return body;
	return JSON.stringify(body);
}

function wrapTransportError(
	err: unknown,
	ctx: { requestId: string; url: string },
): unknown {
	if (err instanceof ApiError || err instanceof ConduitError) return err;
	if (err instanceof TypeError) {
		return new ConduitError("Transport request failed", {
			cause: err,
			code: "transport_error",
			requestId: ctx.requestId,
		});
	}
	return new ConduitError("Unexpected transport failure", {
		cause: err,
		code: "transport_error",
		requestId: ctx.requestId,
	});
}

class Transport {
	private readonly opts: TransportOptions;
	private readonly fetchImpl: typeof fetch;

	constructor(opts: TransportOptions) {
		this.opts = opts;
		this.fetchImpl = opts.fetch ?? fetch;
	}

	private authHeaderName(): string {
		return this.opts.authHeaderName ?? "Mappa-Api-Key";
	}

	get timeoutMs(): number {
		return this.opts.timeoutMs;
	}

	async *streamSSE<T>(
		path: string,
		opts?: SSEStreamOptions,
	): AsyncGenerator<SSEEvent<T>> {
		const url = buildUrl(this.opts.baseUrl, path);
		const requestId = randomId("req");
		const maxRetries = Math.max(0, this.opts.maxRetries);
		const headers = this.createSseHeaders(requestId, opts?.lastEventId);

		let res: Response | undefined;
		let lastError: unknown;

		for (const attempt of Array.from({ length: maxRetries + 1 }, (_, i) => i)) {
			try {
				// biome-ignore lint/performance/noAwaitInLoops: SSE reconnect attempts must respect retry order/backoff
				res = await this.openSseAttempt({
					attempt,
					headers,
					lastEventId: opts?.lastEventId,
					requestId,
					signal: opts?.signal,
					url,
				});
				break;
			} catch (err) {
				lastError = err;
				this.opts.telemetry?.onError?.({
					context: { attempt, lastEventId: opts?.lastEventId },
					error: err,
					requestId,
					url,
				});
				if (this.shouldRetrySseAttempt(err, attempt, maxRetries)) {
					const delay = jitter(backoffMs(attempt + 1, 500, 4000));
					await new Promise((r) => setTimeout(r, delay));
					continue;
				}
				throw err;
			}
		}

		if (!res) throw lastError;
		if (!res.body) {
			throw new ConduitError("SSE response has no body", {
				code: "stream_error",
			});
		}
		yield* this.parseSSEStream<T>(res.body);
	}

	private createSseHeaders(requestId: string, lastEventId?: string) {
		const headers: Record<string, string> = {
			Accept: "text/event-stream",
			"Cache-Control": "no-cache",
			[this.authHeaderName()]: this.opts.apiKey,
			"X-Request-Id": requestId,
			...(this.opts.userAgent ? { "User-Agent": this.opts.userAgent } : {}),
			...(this.opts.defaultHeaders ?? {}),
		};
		if (lastEventId) {
			headers["Last-Event-ID"] = lastEventId;
		}
		return headers;
	}

	private async openSseAttempt(opts: {
		url: string;
		headers: Record<string, string>;
		requestId: string;
		attempt: number;
		signal?: AbortSignal;
		lastEventId?: string;
	}): Promise<Response> {
		const deadline = withDeadline(this.opts.timeoutMs, { signal: opts.signal });
		this.opts.telemetry?.onRequest?.({
			method: "GET",
			requestId: opts.requestId,
			url: opts.url,
		});
		try {
			let res: Response;
			try {
				res = await this.fetchImpl(opts.url, {
					headers: opts.headers,
					method: "GET",
					signal: deadline.signal,
				});
			} catch (cause) {
				if (
					deadline.signal.aborted &&
					deadline.signal.reason instanceof Error
				) {
					throw deadline.signal.reason;
				}
				throw cause;
			}
			if (res.ok) {
				return res;
			}
			const { parsed } = await readBody(res);
			const err = coerceApiError(res, parsed);
			this.opts.telemetry?.onError?.({
				context: { attempt: opts.attempt, lastEventId: opts.lastEventId },
				error: err,
				requestId: opts.requestId,
				url: opts.url,
			});
			throw err;
		} finally {
			deadline.cleanup();
		}
	}

	private shouldRetrySseAttempt(
		err: unknown,
		attempt: number,
		maxRetries: number,
	): boolean {
		if (!(attempt < maxRetries)) return false;
		if (isNetworkError(err)) return true;
		if (!(err instanceof ApiError)) return false;
		return err.status >= 500 && err.status <= 599;
	}

	private async *parseSSEStream<T>(
		body: ReadableStream<Uint8Array>,
	): AsyncGenerator<SSEEvent<T>> {
		const decoder = new TextDecoder();
		const reader = body.getReader();
		let buf = "";

		try {
			for (;;) {
				// biome-ignore lint/performance/noAwaitInLoops: stream reader is sequential by protocol
				const { done, value } = await reader.read();
				if (done) break;
				buf += decoder.decode(value, { stream: true });
				const parts = buf.split("\n\n");
				buf = parts.pop() ?? "";
				yield* this.parseSSEParts<T>(parts);
			}

			if (buf.trim()) {
				yield* this.parseSSEParts<T>([buf]);
			}
		} finally {
			reader.releaseLock();
		}
	}

	private *parseSSEParts<T>(parts: string[]) {
		for (const part of parts) {
			if (!part.trim()) continue;
			const event = this.parseSSEEvent<T>(part);
			if (event) yield event;
		}
	}

	private parseSSEEvent<T>(text: string): SSEEvent<T> | null {
		const lines = text.split("\n");
		let id: string | undefined;
		let event = "message";
		let data = "";

		for (const line of lines) {
			if (line.startsWith("id:")) id = line.slice(3).trim();
			if (line.startsWith("event:")) event = line.slice(6).trim();
			if (!line.startsWith("data:")) continue;
			if (data) data += "\n";
			data += line.slice(5).trim();
		}

		if (!data) return null;
		try {
			return { data: JSON.parse(data) as T, event, id };
		} catch {
			return { data: data as T, event, id };
		}
	}

	async request<T>(req: RequestOptions): Promise<TransportResponse<T>> {
		const url = buildUrl(this.opts.baseUrl, req.path, req.query);
		const requestId = req.requestId ?? randomId("req");
		const headers = this.createRequestHeaders(req, requestId);
		const body = encodeRequestBody(req.body);
		const maxRetries = Math.max(0, this.opts.maxRetries);
		const start = Date.now();

		for (const attempt of Array.from(
			{ length: maxRetries + 1 },
			(_, i) => i + 1,
		)) {
			try {
				// biome-ignore lint/performance/noAwaitInLoops: retry loop requires ordered attempts and backoff
				const res = await this.requestAttempt({
					body,
					headers,
					req,
					requestId,
					start,
					url,
				});
				return res as TransportResponse<T>;
			} catch (err) {
				this.opts.telemetry?.onError?.({ error: err, requestId, url });
				const decision = shouldRetry(req, err);
				if (attempt <= maxRetries && decision.retry) {
					const sleep =
						decision.retryAfterMs ?? jitter(backoffMs(attempt, 500, 4000));
					await new Promise((r) => setTimeout(r, sleep));
					continue;
				}
				throw wrapTransportError(err, { requestId, url });
			}
		}

		throw new ConduitError("Unexpected transport exit", {
			code: "transport_error",
			requestId,
		});
	}

	private createRequestHeaders(req: RequestOptions, requestId: string) {
		const headers: Record<string, string> = {
			[this.authHeaderName()]: this.opts.apiKey,
			"X-Request-Id": requestId,
			...(this.opts.userAgent ? { "User-Agent": this.opts.userAgent } : {}),
			...(this.opts.defaultHeaders ?? {}),
		};
		if (req.idempotencyKey) {
			headers["Idempotency-Key"] = req.idempotencyKey;
		}
		if (req.headers) {
			for (const [k, v] of Object.entries(req.headers)) {
				if (v !== undefined) {
					headers[k] = v;
				}
			}
		}
		const isFormData =
			typeof FormData !== "undefined" && req.body instanceof FormData;
		if (req.body !== undefined && !isFormData) {
			headers["Content-Type"] = "application/json";
		}
		return headers;
	}

	private async requestAttempt(opts: {
		url: string;
		req: RequestOptions;
		headers: Record<string, string>;
		body: ReturnType<typeof encodeRequestBody>;
		requestId: string;
		start: number;
	}): Promise<TransportResponse<unknown>> {
		const deadline = withDeadline(this.opts.timeoutMs, {
			signal: opts.req.signal,
		});
		this.opts.telemetry?.onRequest?.({
			method: opts.req.method,
			requestId: opts.requestId,
			url: opts.url,
		});
		try {
			let res: Response;
			try {
				res = await this.fetchImpl(opts.url, {
					body: opts.body,
					headers: opts.headers,
					method: opts.req.method,
					signal: deadline.signal,
				});
			} catch (cause) {
				if (
					deadline.signal.aborted &&
					deadline.signal.reason instanceof Error
				) {
					throw deadline.signal.reason;
				}
				throw cause;
			}
			const serverRequestId =
				getHeader(res.headers, "x-request-id") ?? opts.requestId;
			if (!res.ok) {
				const { parsed } = await readBody(res);
				const err = coerceApiError(res, parsed);
				this.opts.telemetry?.onError?.({
					error: err,
					requestId: serverRequestId,
					url: opts.url,
				});
				throw err;
			}
			const data = await this.parseResponseData(res);
			this.opts.telemetry?.onResponse?.({
				durationMs: Date.now() - opts.start,
				requestId: serverRequestId,
				status: res.status,
				url: opts.url,
			});
			return {
				data,
				headers: res.headers,
				requestId: serverRequestId,
				status: res.status,
			};
		} finally {
			deadline.cleanup();
		}
	}

	private parseResponseData(res: Response): Promise<unknown> {
		const ct = res.headers.get("content-type") ?? "";
		if (ct.includes("application/json")) {
			return res.json();
		}
		return res.text();
	}
}

export type {
	RequestOptions,
	SSEEvent,
	SSEStreamOptions,
	Telemetry,
	TransportOptions,
	TransportResponse,
};
export { Transport };
